mapper.select:
SELECT application_id, user_id, leave_start_date, leave_end_date, leave_duration_type, leave_type, reason, status, created_at, updated_at, approved_at, approved_by, is_deleted
FROM leave_applications
WHERE user_id = #{userId}
AND leave_start_date <= #{endDate}
AND leave_end_date >= #{startDate}
AND is_deleted = false
ORDER BY leave_start_date ASC
